import { EventBus } from 'event-bus';
import { createReducer } from './reducer';
export class Store {
  constructor() { this.bus = new EventBus(); this.reducer = createReducer(); this.data = {}; }
  get(key) { return this.data[key]; }
  set(key, value) { this.data[key] = value; this.bus.emit('change', key); }
}
